<template><div class="panel"><div class="section-head"><div><h2>{{ t('routes.title') }}</h2><p>{{ t('routes.description') }}</p></div><el-button type="primary" @click="open()">{{ t('routes.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="featureCode" :label="t('routes.featureCode')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column prop="capabilityLevel" :label="t('models.capability')"/><el-table-column prop="thinkingLevel" :label="t('routes.thinkingLevel')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('routes.edit'):t('routes.add')"><el-form label-width="110px"><el-form-item :label="t('routes.featureCode')"><el-input v-model="form.featureCode"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item :label="t('routes.providerPool')"><el-select v-model="form.providerIds" multiple><el-option v-for="item in providers" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item :label="t('models.capability')"><el-select v-model="form.capabilityLevel"><el-option label="Low" value="LOW"/><el-option label="Medium" value="MIDDLE"/><el-option label="High" value="HIGH"/></el-select></el-form-item><el-form-item :label="t('routes.thinking')"><el-switch v-model="form.enableThinking"/></el-form-item><el-form-item v-if="form.enableThinking" :label="t('routes.thinkingLevel')"><el-select v-model="form.thinkingLevel"><el-option v-for="level in levels" :key="level" :label="level" :value="level"/></el-select></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';const{t}=useI18n(),rows=ref([]),providers=ref([]),visible=ref(false),levels=['LOW','MEDIUM','HIGH','EXTRA_HIGH','MAX','ULTRA'],form=reactive({id:null,featureCode:'',name:'',candidateModelIds:[],providerIds:[],capabilityLevel:'MIDDLE',enableThinking:false,thinkingLevel:'MEDIUM',enabled:true});async function load(){[rows.value,providers.value]=await Promise.all([http.get('/models/routes').then(r=>r.data),http.get('/models/providers').then(r=>r.data)])}function open(row){Object.assign(form,row?{...row,providerIds:[...(row.providerIds||[])]}:{id:null,featureCode:'',name:'',candidateModelIds:[],providerIds:[],capabilityLevel:'MIDDLE',enableThinking:false,thinkingLevel:'MEDIUM',enabled:true});visible.value=true}async function save(){form.id?await http.put(`/models/routes/${form.id}`,form):await http.post('/models/routes',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}onMounted(load)</script>
